import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import Cookie from "cookie-universal";
import Axios, { ADMIN_ENROLLMENTS, ADMIN_COURSE_STUDENTS } from "../../Api/Api";
import "../../Styles/Dashboard.css";

export default function EnrollmentManagement() {
  const navigate = useNavigate();
  const cookie = Cookie();

  const [courses, setCourses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [selectedCourse, setSelectedCourse] = useState(null);
  const [students, setStudents] = useState([]);
  const [studentsLoading, setStudentsLoading] = useState(false);

  // التحقق من الأدمن
  useEffect(() => {
    const user = cookie.get("educational-user");
    if (!user) {
      navigate("/login");
      return;
    }

    const userData = typeof user === "string" ? JSON.parse(user) : user;
    if (userData.role !== "admin") {
      alert("غير مصرح لك بالوصول لهذه الصفحة");
      navigate("/");
      return;
    }

    loadCourses();
  }, []);

  // جلب الكورسات مع عدد المسجلين
  function loadCourses() {
    setLoading(true);
    Axios.get(`/${ADMIN_ENROLLMENTS}`)
      .then((res) => {
        setCourses(res.data);
        setLoading(false);
      })
      .catch((err) => {
        console.error(err);
        setLoading(false);
      });
  }

  // عرض طلاب كورس معين
  async function viewStudents(course) {
    setSelectedCourse(course);
    setShowModal(true);
    setStudentsLoading(true);

    try {
      const res = await Axios.get(
        `/${ADMIN_COURSE_STUDENTS}/${course.id}/students`,
      );
      setStudents(res.data.students);
      setStudentsLoading(false);
    } catch (err) {
      console.error(err);
      setStudentsLoading(false);
    }
  }

  // إغلاق Modal
  function closeModal() {
    setShowModal(false);
    setSelectedCourse(null);
    setStudents([]);
  }

  // حساب الإحصائيات
  const totalStudents = courses.reduce(
    (sum, c) => sum + (c.users_count || 0),
    0,
  );
  const coursesWithStudents = courses.filter((c) => c.users_count > 0).length;

  if (loading) {
    return (
      <div className="loading-container">
        <div className="spinner"></div>
        <p>جاري التحميل...</p>
      </div>
    );
  }

  return (
    <div className="dashboard-page">
      {/* Header */}
      <div className="dashboard-header">
        <div className="header-content">
          <div className="header-text">
            <h1>الكورسات المسجلة 📋</h1>
            <p>عرض الطلاب المسجلين في كل كورس</p>
          </div>
        </div>
      </div>

      {/* Content */}
      <div className="dashboard-content">
        <div className="container">
          {/* Navigation */}
          <div className="dashboard-nav">
            <button onClick={() => navigate("/dashboard")} className="nav-btn">
              📚 إدارة الكورسات
            </button>
            <button
              onClick={() => navigate("/dashboard/instructors")}
              className="nav-btn"
            >
              👨‍🏫 إدارة المدرسين
            </button>
            <button
              onClick={() => navigate("/dashboard/users")}
              className="nav-btn"
            >
              👥 إدارة المستخدمين
            </button>
            <button
              onClick={() => navigate("/dashboard/enrollments")}
              className="nav-btn active"
            >
              📋 الكورسات المسجلة
            </button>
          </div>

          {/* Stats */}
          <div className="stats-cards">
            <div className="stat-card">
              <h3>إجمالي التسجيلات</h3>
              <p className="stat-number">{totalStudents}</p>
            </div>
            <div className="stat-card">
              <h3>كورسات فيها طلاب</h3>
              <p className="stat-number">{coursesWithStudents}</p>
            </div>
            <div className="stat-card">
              <h3>كورسات بدون طلاب</h3>
              <p className="stat-number">
                {courses.length - coursesWithStudents}
              </p>
            </div>
          </div>

          {/* Table */}
          <div className="table-container">
            <table className="courses-table">
              <thead>
                <tr>
                  <th>#</th>
                  <th>الكورس</th>
                  <th>المدرب</th>
                  <th>السعر</th>
                  <th>عدد المسجلين</th>
                  <th>الإجراءات</th>
                </tr>
              </thead>
              <tbody>
                {courses.map((course, index) => (
                  <tr key={course.id}>
                    <td>{index + 1}</td>
                    <td className="course-title-cell">{course.title}</td>
                    <td>{course.instructor ? course.instructor.name : "-"}</td>
                    <td className="price-cell">${course.price}</td>
                    <td>
                      <span
                        className={`badge ${course.users_count > 0 ? "featured" : ""}`}
                      >
                        {course.users_count || 0} طالب
                      </span>
                    </td>
                    <td>
                      <button
                        onClick={() => viewStudents(course)}
                        className="edit-btn"
                        title="عرض الطلاب"
                        disabled={course.users_count === 0}
                      >
                        👁️ عرض
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>

      {/* Modal - عرض الطلاب */}
      {showModal && (
        <div className="modal-overlay" onClick={closeModal}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h2>👥 طلاب كورس: {selectedCourse?.title}</h2>
              <button onClick={closeModal} className="close-btn">
                ✖
              </button>
            </div>

            <div className="modal-body">
              {studentsLoading ? (
                <div className="loading-container">
                  <div className="spinner"></div>
                  <p>جاري التحميل...</p>
                </div>
              ) : students.length === 0 ? (
                <p className="empty-message">لا يوجد طلاب مسجلين</p>
              ) : (
                <table className="courses-table">
                  <thead>
                    <tr>
                      <th>#</th>
                      <th>الاسم</th>
                      <th>البريد الإلكتروني</th>
                      <th>تاريخ التسجيل</th>
                    </tr>
                  </thead>
                  <tbody>
                    {students.map((student, index) => (
                      <tr key={student.id}>
                        <td>{index + 1}</td>
                        <td>{student.name}</td>
                        <td>{student.email}</td>
                        <td>
                          {student.pivot?.enrolled_at
                            ? new Date(
                                student.pivot.enrolled_at,
                              ).toLocaleDateString("ar-EG")
                            : "-"}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              )}
            </div>

            <div className="modal-footer">
              <button onClick={closeModal} className="cancel-btn">
                إغلاق
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
